#!/usr/bin/env python3
"""
EQL Hunting Log v0.2.3 - self-extracting installer
------------------------------------------------
Run this file (double-click on Windows, or: python EQL_Hunting_Log_installer_v0.2.3.py).
It creates an "EQL Hunting Log" folder next to itself containing the tracker
app, README, and changelog, then offers to launch the app. Nothing is
installed system-wide; delete the folder to remove everything.
"""
import base64, io, os, sys, zipfile

PAYLOAD = ""

def main():
    here = os.path.dirname(os.path.abspath(sys.argv[0])) or "."
    target = os.path.join(here, "EQL Hunting Log")
    os.makedirs(target, exist_ok=True)
    z = zipfile.ZipFile(io.BytesIO(base64.b64decode(PAYLOAD)))
    names = z.namelist()
    existing = [n for n in names if os.path.exists(os.path.join(target, n))]
    if existing:
        ans = input("Some files already exist in %s\nOverwrite the app files? "
                    "(your data files are never touched) [y/N] " % target)
        if ans.strip().lower() != "y":
            print("Cancelled. Nothing was changed.")
            input("Press Enter to close.")
            return
    z.extractall(target)
    print("\nExtracted to: %s" % target)
    for n in names:
        print("  - %s" % n)
    print("\nYour config, stats, kill history, and quest data will be created")
    print("in that folder on first run and are preserved by future updates.")
    app = os.path.join(target, "eql_tracker_app_v0.2.3.pyw")
    try:
        ans = input("\nLaunch EQL Hunting Log now? [Y/n] ")
        if ans.strip().lower() in ("", "y", "yes"):
            if sys.platform == "win32":
                os.startfile(app)
            else:
                import subprocess
                subprocess.Popen([sys.executable, app])
            print("Launched. Happy hunting.")
        else:
            print("Run %s whenever you are ready." % app)
    except Exception as e:
        print("Could not auto-launch (%r) - start it manually:" % e)
        print("  %s" % app)
    input("Press Enter to close.")

if __name__ == "__main__":
    main()
